// src/services/api.js
import axios from 'axios';

// 1. Create the Axios instance pointing to Django
const apiClient = axios.create({
  // This is the absolute URL to your Django server
  baseURL: 'http://localhost:8000/api/',
  headers: {
    'Content-Type': 'application/json',
  },
});

// 2. Intercept requests to attach the Auth token (for when users log in)
apiClient.interceptors.request.use((config) => {
  const token = localStorage.getItem('token');
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
});

// 3. Export the API calls your Redux slices are expecting
export const productAPI = {
  // Hits: http://localhost:8000/api/products/
  list: (params) => apiClient.get('products/', { params }),

  // Hits: http://localhost:8000/api/products/<slug>/
  detail: (slug) => apiClient.get(`products/${slug}/`),

  // Hits: http://localhost:8000/api/categories/
  categories: () => apiClient.get('categories/')
};

export const authAPI = {
  sendOtp: (data) => apiClient.post('auth/send-otp/', data),
  verifyOtp: (data) => apiClient.post('auth/verify-otp/', data),
  me: () => apiClient.get('auth/me/')
};

export default apiClient;
